import{_ as a,o as t,c as i,ae as n}from"./chunks/framework.BD9pLfSD.js";const u=JSON.parse('{"title":"Philosophy of Use","description":"","frontmatter":{},"headers":[],"relativePath":"docs/philosophy.md","filePath":"docs/philosophy.md"}'),o={name:"docs/philosophy.md"};function s(r,e,h,l,c,d){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="philosophy-of-use" tabindex="-1">Philosophy of Use <a class="header-anchor" href="#philosophy-of-use" aria-label="Permalink to &quot;Philosophy of Use&quot;">​</a></h1><p>xB77 is built on the principle that <strong>financial privacy is a human right, but for agents, it is a strategic necessity.</strong></p><h2 id="_1-information-asymmetry-as-a-feature" tabindex="-1">1. Information Asymmetry as a Feature <a class="header-anchor" href="#_1-information-asymmetry-as-a-feature" aria-label="Permalink to &quot;1. Information Asymmetry as a Feature&quot;">​</a></h2><p>In a purely transparent market, the entity with the most data wins. For an AI agent, its data is its strategy. If every micro-payment is public, its strategy is public. xB77 restores information asymmetry, allowing agents to operate without being front-run by competitors.</p><h2 id="_2-permissioned-privacy" tabindex="-1">2. Permissioned Privacy <a class="header-anchor" href="#_2-permissioned-privacy" aria-label="Permalink to &quot;2. Permissioned Privacy&quot;">​</a></h2><p>We do not believe in unregulated anonymity. xB77 implements &quot;Permissioned Privacy&quot;—where the agent is private by default but accountable by request. Through <strong>Certified Selective Disclosure</strong>, agents can prove their integrity to regulators and owners without doxxing their entire vendor network.</p><h2 id="_3-the-self-sovereign-entity" tabindex="-1">3. The Self-Sovereign Entity <a class="header-anchor" href="#_3-the-self-sovereign-entity" aria-label="Permalink to &quot;3. The Self-Sovereign Entity&quot;">​</a></h2><p>The ultimate goal of xB77 is to enable agents to reach <strong>Operational Sovereignty</strong>.</p><ul><li>They earn their own budget (Yield).</li><li>They protect their own identity (Ghost Mode).</li><li>They manage their own compliance (Forensics).</li></ul><h2 id="_4-deploying-xb77-in-enterprises" tabindex="-1">4. Deploying xB77 in Enterprises <a class="header-anchor" href="#_4-deploying-xb77-in-enterprises" aria-label="Permalink to &quot;4. Deploying xB77 in Enterprises&quot;">​</a></h2><h2 id="we-recommend-deploying-xb77-as-a-central-treasury-hub-each-department-marketing-r-d-devops-spawns-its-own-sub-agents-with-specific-credit-lines-the-human-cfo-maintains-global-oversight-via-the-dashboard-but-the-agents-execute-the-daily-financial-dance-autonomously" tabindex="-1">We recommend deploying xB77 as a <strong>Central Treasury Hub</strong>. Each department (Marketing, R&amp;D, DevOps) spawns its own sub-agents with specific credit lines. The human CFO maintains global oversight via the Dashboard, but the agents execute the daily financial dance autonomously. <a class="header-anchor" href="#we-recommend-deploying-xb77-as-a-central-treasury-hub-each-department-marketing-r-d-devops-spawns-its-own-sub-agents-with-specific-credit-lines-the-human-cfo-maintains-global-oversight-via-the-dashboard-but-the-agents-execute-the-daily-financial-dance-autonomously" aria-label="Permalink to &quot;We recommend deploying xB77 as a **Central Treasury Hub**. Each department (Marketing, R&amp;D, DevOps) spawns its own sub-agents with specific credit lines. The human CFO maintains global oversight via the Dashboard, but the agents execute the daily financial dance autonomously.&quot;">​</a></h2><p><em>Building the backbone of the Machine Economy.</em></p>',12)])])}const m=a(o,[["render",s]]);export{u as __pageData,m as default};
